import{_ as t,c as a,o as i,aj as s}from"./chunks/framework.ByJOsj0O.js";const g=JSON.parse('{"title":"Performance","description":"","frontmatter":{},"headers":[],"relativePath":"guide/performance.md","filePath":"guide/performance.md","lastUpdated":1784062481000}'),n={name:"guide/performance.md"};function r(l,e,o,c,d,h){return i(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h1><p>Scanic is built to be fast and small. This page covers how it achieves that and how to tune it for your workload.</p><h2 id="how-it-compares" tabindex="-1">How it compares <a class="header-anchor" href="#how-it-compares" aria-label="Permalink to &quot;How it compares&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">Scanic</th><th style="text-align:left;">jscanify</th><th style="text-align:left;">OpenCV.js</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Download size</strong></td><td style="text-align:left;"><strong>~100KB</strong></td><td style="text-align:left;">~31MB</td><td style="text-align:left;">~30MB</td></tr><tr><td style="text-align:left;"><strong>Perspective speed</strong></td><td style="text-align:left;"><strong>~10ms</strong></td><td style="text-align:left;">~200ms</td><td style="text-align:left;">~5ms</td></tr><tr><td style="text-align:left;"><strong>WASM optimized</strong></td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;"><strong>TypeScript</strong></td><td style="text-align:left;">✅</td><td style="text-align:left;">❌</td><td style="text-align:left;">✅</td></tr></tbody></table><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><p>Scanic uses a <strong>hybrid JavaScript + WebAssembly</strong> approach:</p><ul><li><strong>JavaScript layer</strong>: high-level API, DOM/canvas handling, contour logic, workflow coordination.</li><li><strong>WebAssembly layer</strong>: the CPU-intensive inner loops: <ul><li>Gaussian blur with SIMD</li><li>Canny edge detection with hysteresis thresholding</li><li>Sobel gradient calculations</li><li>Non-maximum suppression (edge thinning)</li><li>Morphological dilation</li></ul></li></ul><p>The perspective warp uses a <strong>per-pixel bilinear inverse-map</strong>: for each output pixel, the inverse perspective matrix locates the corresponding source coordinate, which is then bilinearly sampled directly via <code>ImageData</code>. This completes in roughly <strong>10ms</strong>, versus 500ms+ for a naive forward per-pixel loop and versus the older GPU/Canvas triangle-subdivision approach it replaced, which also had visible seam artifacts.</p><h2 id="tuning-tips" tabindex="-1">Tuning tips <a class="header-anchor" href="#tuning-tips" aria-label="Permalink to &quot;Tuning tips&quot;">​</a></h2><ul><li><strong>Downscale for detection.</strong> <a href="/scanic/api/reference#options"><code>maxProcessingDimension</code></a> (default 800) caps the size Scanic detects on. Lower it (600) for speed, raise it (1200) for sharper corner accuracy on large images. Corners are scaled back to full resolution automatically.</li><li><strong>Reuse a <code>Scanner</code>.</strong> The <a href="/scanic/api/reference#scanner"><code>Scanner</code></a> class keeps the WASM instance warm. Essential for webcams and batch jobs. Call <code>initialize()</code> once.</li><li><strong>Detect, then extract.</strong> In live preview, run <code>mode: &#39;detect&#39;</code> on a fraction of frames and only <code>extract</code> on capture.</li><li><strong>Mind the cascade.</strong> <a href="/scanic/api/reference#options"><code>enableDetectionCascade</code></a> retries hard images with extra passes. It improves accuracy but costs time; disable it if you control image quality and need maximum throughput.</li></ul><h2 id="measuring" tabindex="-1">Measuring <a class="header-anchor" href="#measuring" aria-label="Permalink to &quot;Measuring&quot;">​</a></h2><p>Every result includes a <code>timings</code> array with a per-step breakdown:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> result</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> scanDocument</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(img, { mode: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;extract&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> })</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">console.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">table</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(result.timings) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// [{ step, ms }, ...]</span></span></code></pre></div>`,13)])])}const u=t(n,[["render",r]]);export{g as __pageData,u as default};
